const { sql } = require('slonik');

async function solve({ difficulty, limit, tags }) {
  // Normalize difficulty filter
  const difficultyFilter = difficulty ? difficulty.toUpperCase() : null;

  // Normalize tags filter: accept comma-separated string or array, case-insensitive
  let normalizedTags = [];
  if (tags) {
    if (Array.isArray(tags)) {
      normalizedTags = tags
        .flatMap(t => t.split(','))
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    } else if (typeof tags === 'string') {
      normalizedTags = tags
        .split(',')
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    }
  }

  // Compose WHERE clauses
  const whereClauses = [];
  const params = {};

  if (difficultyFilter) {
    whereClauses.push(sql`p.difficulty = ${difficultyFilter}`);
  }

  if (normalizedTags.length > 0) {
    // Filter problems that have at least one of the tags (case-insensitive)
    whereClauses.push(sql`EXISTS (
      SELECT 1 FROM problem_tags pt
      WHERE pt.problem_id = p.id
      AND LOWER(pt.tag) = ANY(${normalizedTags})
    )`);
  }

  // Compose final WHERE clause
  const whereSql = whereClauses.length > 0 ? sql`WHERE ${sql.join(whereClauses, sql` AND `)}` : sql``;

  // Query problems with stable ordering by roundId, id
  const limitSql = limit ? sql`LIMIT ${limit}` : sql``;

  const query = sql`
    SELECT p.*, 
      ARRAY(
        SELECT DISTINCT LOWER(pt.tag)
        FROM problem_tags pt
        WHERE pt.problem_id = p.id
      ) AS normalized_tags
    FROM problems p
    ${whereSql}
    ORDER BY p.round_id, p.id
    ${limitSql}
  `;

  const problems = await this.db.any(query);

  // Compose metadata with appliedTags normalized and unique
  const appliedTags = [...new Set(normalizedTags)];

  return {
    problems,
    metadata: {
      appliedTags,
    },
  };
}

module.exports = {
  solve,
};
